import { useState } from "react";

export default function Terminal() {
  const [cmd, setCmd] = useState("");
  const [history, setHistory] = useState([]);

  const runCommand = (e) => {
    // 1. Зупини стандартну подію
    e.preventDefault();
    // 2. Перевір на порожнечу
    if (!cmd.trim()) return;
    // 3. Онови масив history (через spread оператор)
    setHistory(() => [...history, cmd]);
    // 4. Очисти cmd
    setCmd("");
  };

  return (
    <div
      style={{
        background: "#000",
        color: "#0f0",
        padding: "20px",
        fontFamily: "monospace",
      }}
    >
      <form onSubmit={runCommand}>
        <span>$ </span>
        <input
          type="text"
          value={cmd}
          onChange={(e) => setCmd(e.target.value)}
          style={{
            background: "transparent",
            border: "none",
            color: "#0f0",
            outline: "none",
          }}
          autoFocus
        />
      </form>

      <div style={{ marginTop: "20px" }}>
        {history.map((obj) => (
          <p>{obj}</p>
        ))}
      </div>
    </div>
  );
}
